<?php require "vendor/autoload.php"; $app = require "bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $ujian = App\Models\Ujian::find(10); $now = \Carbon\Carbon::now(); $start = \Carbon\Carbon::parse($ujian->tanggal_ujian . " " . $ujian->jam_mulai); $end = \Carbon\Carbon::parse($ujian->tanggal_ujian . " " . $ujian->jam_selesai); if ($end->lt($start)) { $end->addDay(); } $sisaWaktuDetik = $ujian->durasi * 60; $sisaSampaiTutup = $end->diffInSeconds($now); if ($sisaWaktuDetik > $sisaSampaiTutup) { $sisaWaktuDetik = $sisaSampaiTutup; } echo json_encode(compact("now", "start", "end", "sisaWaktuDetik", "sisaSampaiTutup"));
